// 在演奏阶段预览原曲（Toggle 模式）
function playTargetPreview(btn) {
    initAudioContext();
    initMasterMixer();

    if (!gameState.isPlayingOriginal) {
        // ===== 第一次点击：开始循环播放原曲 =====
        gameState.isPlayingOriginal = true;

        // 停止当前用户选择
        stopAllMusic();
        stopUserProgressBar(); // 停止用户进度条

        // 立即播放目标组合（不等待乐句边界）
        parts.forEach(part => {
            setSwitch(part, gameState.targetCombination[part], true);
        });

        // 更新按钮状态为"关闭"
        btn.innerHTML = '🔊 关闭原曲';
        btn.classList.remove('btn-secondary');
        btn.classList.add('btn-warning');

        // 显示并启动原曲进度条
        startOriginalProgressBar();

    } else {
        // ===== 第二次点击：停止原曲，恢复用户选择 =====
        gameState.isPlayingOriginal = false;

        // 停止原曲
        stopAllMusic();
        stopOriginalProgressBar(); // 停止原曲进度条

        // 恢复用户的选择
        const hasSelection = parts.some(p => gameState.userSelection[p]);
        if (hasSelection) {
            parts.forEach(p => {
                if (gameState.userSelection[p]) {
                    setSwitch(p, gameState.userSelection[p], true);
                }
            });
            // 启动用户进度条
            startUserProgressBar();
        }

        // 恢复按钮状态
        btn.innerHTML = '🎯 再听原曲';
        btn.classList.remove('btn-warning');
        btn.classList.add('btn-secondary');
    }
}

// ===== 原曲进度条控制 =====
function startOriginalProgressBar() {
    const container = document.getElementById('originalProgressContainer');
    const bar = document.getElementById('originalProgressBar');
    container.style.display = 'block';

    const loopDuration = 4000; // 4秒一个loop
    let startTime = Date.now();

    gameState.originalProgressInterval = setInterval(() => {
        const elapsed = Date.now() - startTime;
        const progress = (elapsed % loopDuration) / loopDuration * 100;
        bar.style.width = progress + '%';
    }, 50); // 50ms更新一次
