        function resetLevel() {
            // 重置选择
            gameState.userSelection = { melody: null, harmony: null, bass: null, drums: null };

            // 重置"再听原曲"按钮状态
            gameState.isPlayingOriginal = false;
            const previewBtn = document.querySelector('button[onclick="playTargetPreview(this)"]');
            if (previewBtn) {
                previewBtn.innerHTML = '🎯 再听原曲';
                previewBtn.classList.remove('btn-warning');
                previewBtn.classList.add('btn-secondary');
            }

            // 重置UI
            parts.forEach(part => {
                document.getElementById(part + 'Status').classList.remove('playing');
                document.getElementById(part + 'Section').classList.remove('active');
                document.getElementById('summary' + part.charAt(0).toUpperCase() + part.slice(1)).textContent = '未选择';
                document.getElementById('summary' + part.charAt(0).toUpperCase() + part.slice(1)).classList.remove('selected');

                const optionsContainer = document.getElementById(part + 'Options');
                optionsContainer.querySelectorAll('.part-option').forEach(opt => {
                    opt.classList.remove('selected');
                });
            });

            updateMixerDisplay();

            // 返回第一阶段
            gameState.currentPhase = 1;
            updateStageIndicator();

            document.getElementById('phase3').style.display = 'none';
            document.getElementById('phase2').style.display = 'none';
            document.getElementById('phase1').style.display = 'block';
            document.getElementById('verifyActions').style.display = 'none';

            // 生成新目标
            generateTargetCombination();

            // 自动播放目标音乐
            setTimeout(() => {
                playTargetCombination(true);
                animateVisualizer('targetVisualizer', true);
            }, 300);
        }

        function updateStageIndicator() {
            for (let i = 1; i <= 3; i++) {
                const dot = document.getElementById('stage' + i);
                dot.classList.remove('active', 'completed');

                if (i < gameState.currentPhase) {
                    dot.classList.add('completed');
                } else if (i === gameState.currentPhase) {
                    dot.classList.add('active');
                }
            }
