// 预热音频系统，消除首次播放延迟
function warmupAudioSystem() {
    if (!gameState.audioContext) return;

    const now = gameState.audioContext.currentTime;

    // 预热：创建一个极短的无声音符来激活音频管线
    const osc = gameState.audioContext.createOscillator();
    const gain = gameState.audioContext.createGain();
    gain.gain.value = 0.001; // 几乎无声
    osc.connect(gain);
    gain.connect(gameState.audioContext.destination);
    osc.start(now);
    osc.stop(now + 0.001);

    // 预热所有轨道增益节点
    initMasterMixer();

    // 预生成一个音符来初始化合成器
    parts.forEach(part => {
