// 预热的音频缓存 - 存储已创建的节点
const audioWarmupCache = {
    oscillators: [],
    gains: [],
    isWarmedUp: false
};

// ==================== 关卡预热系统 ====================

// 显示关卡加载界面并预热音频
async function warmupLevelAudio() {
    const loadingOverlay = document.getElementById('levelLoadingOverlay');
    const loadingProgress = document.getElementById('loadingProgress');
    const loadingStatus = document.getElementById('loadingStatus');
    const loadingLevelNum = document.getElementById('loadingLevelNum');

    loadingLevelNum.textContent = gameState.currentLevel;
    loadingOverlay.style.display = 'flex';

    // 步骤1: 确保音频上下文就绪 (20%)
    loadingStatus.textContent = '初始化音频上下文...';
    initAudioContext();
    if (gameState.audioContext.state === 'suspended') {
        await gameState.audioContext.resume();
    }
    loadingProgress.style.width = '20%';
    await sleep(100);

    // 步骤2: 初始化混音器 (40%)
    loadingStatus.textContent = '初始化混音器...';
    initMasterMixer();
    loadingProgress.style.width = '40%';
    await sleep(100);

    // 步骤3: 预热所有声部的所有变体 (80%)
    loadingStatus.textContent = '预热乐器音色...';
    await warmupAllInstruments();
    loadingProgress.style.width = '80%';

    // 步骤4: 静默播放一次目标组合完成最终预热 (100%)
    loadingStatus.textContent = '合成目标音乐...';
    await warmupTargetCombination();
    loadingProgress.style.width = '100%';

    // 隐藏加载界面
    await sleep(200);
    loadingOverlay.style.display = 'none';
    audioWarmupCache.isWarmedUp = true;

    console.log('关卡音频预热完成');
}

// 预热所有乐器
async function warmupAllInstruments() {
    const ctx = gameState.audioContext;
    const now = ctx.currentTime;

    // 为每个声部的每个变体创建一次振荡器（音量设为0）
    for (const part of parts) {
        for (const option of options) {
            // 根据声部类型预热不同的波形
            const oscType = getOscillatorTypeForPart(part);
            const freq = getWarmupFrequency(part, option);

            const osc = ctx.createOscillator();
            const gain = ctx.createGain();

            osc.type = oscType;
            osc.frequency.value = freq;
            gain.gain.value = 0; // 静音

            osc.connect(gain);
            gain.connect(trackGainNodes[part] || ctx.destination);

            // 极短播放来激活节点
            osc.start(now);
            osc.stop(now + 0.001);

            // 缓存引用
            audioWarmupCache.oscillators.push(osc);
            audioWarmupCache.gains.push(gain);
        }
    }

    await sleep(50);
}

// 静默预热目标组合
async function warmupTargetCombination() {
    const ctx = gameState.audioContext;
    const now = ctx.currentTime;

    // 为当前关卡的目标组合的所有声部创建节点
    parts.forEach(part => {
        const state = gameState.targetCombination[part];
        const pattern = getPatternForPart(part, state);

        pattern.forEach((note, i) => {
            if (note && i < 2) { // 只预热前两个音符
                const beatDur = 0.5;
                if (part === 'drums') {
                    createDrumSource(note, now + i * 0.01, 0);
                } else {
                    createNoteSource(noteFrequencies[note] || 440, beatDur * 0.1, now + i * 0.01, 0, getOscillatorTypeForPart(part));
                }
            }
        });
    });

    await sleep(100);
}

// 辅助函数
function getOscillatorTypeForPart(part) {
    const types = { melody: 'sine', harmony: 'triangle', bass: 'triangle', drums: 'sine' };
    return types[part] || 'sine';
}

function getWarmupFrequency(part, option) {
    const freqs = {
        melody: { A: 440, B: 523.25, C: 659.25 },
        harmony: { A: 329.63, B: 392, C: 493.88 },
        bass: { A: 130.81, B: 146.83, C: 164.81 },
        drums: { A: 60, B: 80, C: 100 }
    };
    return freqs[part]?.[option] || 440;
}

function getPatternForPart(part, state) {
    switch(part) {
        case 'melody': return generateMelodyPattern(state);
        case 'harmony': return generateHarmonyPattern(state);
        case 'bass': return generateBassPattern(state);
        case 'drums': return generateDrumsPattern(state);
        default: return [];
    }
}

function sleep(ms) {
    return new Promise(resolve => setTimeout(resolve, ms));
}

