// ==================== 音频预合成系统 ====================

// 用 OfflineAudioContext 预合成一个声部变体的音频
async function renderPartToBuffer(part, option) {
    const duration = 4; // 4秒 loop
    const sampleRate = 44100;
    const offlineCtx = new OfflineAudioContext(1, duration * sampleRate, sampleRate);

    const beatDur = 0.5; // 120 BPM
    const volume = MUSIC_TRACKS[part].volume;

    // 根据声部生成对应的 pattern
    let pattern;
    switch(part) {
        case 'melody': pattern = generateMelodyPattern(option); break;
        case 'harmony': pattern = generateHarmonyPattern(option); break;
        case 'bass': pattern = generateBassPattern(option); break;
        case 'drums': pattern = generateDrumsPattern(option); break;
        default: pattern = [];
    }

    // 合成音频
    pattern.forEach((note, i) => {
        if (!note) return;

        const startTime = i * beatDur;

        if (part === 'drums') {
            // 鼓点合成
            const { osc, gain } = createDrumSourceOffline(offlineCtx, note, startTime, volume);
            if (osc) {
                osc.connect(gain);
                gain.connect(offlineCtx.destination);
            }
        } else {
            // 音符合成
            const freq = noteFrequencies[note] || 440;
            const type = part === 'melody' ? 'sine' : 'triangle';
            const noteDur = part === 'melody' ? beatDur * 0.8 : beatDur * 0.9;

            const osc = offlineCtx.createOscillator();
            const gain = offlineCtx.createGain();

            osc.type = type;
            osc.frequency.value = freq;

            // ADSR 包络
            gain.gain.setValueAtTime(0, startTime);
            gain.gain.linearRampToValueAtTime(volume, startTime + 0.05);
            gain.gain.setValueAtTime(volume, startTime + noteDur - 0.1);
            gain.gain.exponentialRampToValueAtTime(0.001, startTime + noteDur);

            osc.connect(gain);
            gain.connect(offlineCtx.destination);

            osc.start(startTime);
            osc.stop(startTime + noteDur);
        }
    });

    return await offlineCtx.startRendering();
}

// 离线鼓点合成
function createDrumSourceOffline(ctx, drum, startTime, volume) {
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    switch(drum) {
        case 'kick':
            osc.frequency.setValueAtTime(150, startTime);
            osc.frequency.exponentialRampToValueAtTime(0.01, startTime + 0.5);
            gain.gain.setValueAtTime(volume, startTime);
            gain.gain.exponentialRampToValueAtTime(0.01, startTime + 0.5);
            osc.start(startTime);
            osc.stop(startTime + 0.5);
            break;
        case 'snare':
            osc.type = 'triangle';
            osc.frequency.setValueAtTime(200, startTime);
            gain.gain.setValueAtTime(volume * 0.8, startTime);
            gain.gain.exponentialRampToValueAtTime(0.01, startTime + 0.15);
            osc.start(startTime);
            osc.stop(startTime + 0.15);
            break;
        case 'hihat':
            osc.type = 'square';
            osc.frequency.setValueAtTime(800, startTime);
            gain.gain.setValueAtTime(volume * 0.3, startTime);
            gain.gain.exponentialRampToValueAtTime(0.01, startTime + 0.05);
            osc.start(startTime);
            osc.stop(startTime + 0.05);
            break;
        default:
            return { osc: null, gain: null };
    }

    return { osc, gain };
}

// 关卡加载：预合成所有音频
async function preloadLevelAudio() {
    const loadingOverlay = document.getElementById('levelLoadingOverlay');
    const loadingProgress = document.getElementById('loadingProgress');
    const loadingStatus = document.getElementById('loadingStatus');
    const loadingLevelNum = document.getElementById('loadingLevelNum');

    loadingLevelNum.textContent = gameState.currentLevel;
    loadingOverlay.style.display = 'flex';

    // 步骤1: 初始化音频上下文 (20%)
    loadingStatus.textContent = '初始化音频上下文...';
    initAudioContext();
    if (gameState.audioContext.state === 'suspended') {
        await gameState.audioContext.resume();
    }
    loadingProgress.style.width = '20%';

    // 步骤2: 清空旧缓存 (30%)
    audioBufferCache.buffers = {};
    audioBufferCache.isLoaded = false;
    loadingProgress.style.width = '30%';

    // 步骤3: 预合成所有 12 种组合 (30% -> 90%)
    const combinations = [];
    for (const part of parts) {
        for (const option of options) {
            combinations.push({ part, option });
        }
    }

    const total = combinations.length;
    for (let i = 0; i < total; i++) {
        const { part, option } = combinations[i];
        loadingStatus.textContent = `合成音色: ${partNames[part]} ${option} (${i + 1}/${total})`;

        const buffer = await renderPartToBuffer(part, option);
        audioBufferCache.buffers[`${part}-${option}`] = buffer;

        const progress = 30 + Math.floor((i + 1) / total * 60);
        loadingProgress.style.width = progress + '%';
    }

    // 步骤4: 完成 (100%)
    loadingStatus.textContent = '准备就绪!';
    loadingProgress.style.width = '100%';

    await sleep(200);
    loadingOverlay.style.display = 'none';
    audioBufferCache.isLoaded = true;

    console.log('音频预合成完成，缓存了', Object.keys(audioBufferCache.buffers).length, '个buffer');
}

// 使用缓存的 buffer 播放（零延迟）
function playCachedBuffer(part, option, loop = true) {
    const ctx = gameState.audioContext;
    const bufferKey = `${part}-${option}`;
    const buffer = audioBufferCache.buffers[bufferKey];

    if (!buffer) {
        console.error('Buffer not found:', bufferKey);
        return null;
    }

    // 停止该声部的旧播放
    stopMusicVoice(part);

    // 创建 source
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.loop = loop;

    // 连接到轨道增益节点
    if (!trackGainNodes[part]) {
        initMasterMixer();
    }
    source.connect(trackGainNodes[part]);

    source.start(0);

    // 保存引用
    activeMusicVoices[part] = { source };

    return source;
}

function sleep(ms) {
    return new Promise(resolve => setTimeout(resolve, ms));
}

