// 用 OfflineAudioContext 预合成一个声部变体
async function renderPartBuffer(part, option) {
    const duration = 4; // 4秒 loop
    const sampleRate = 44100;
    const ctx = new OfflineAudioContext(1, duration * sampleRate, sampleRate);

    const beatDur = 0.5;
    const volume = MUSIC_TRACKS[part].volume;

    // 获取 pattern
    let pattern;
    switch(part) {
        case 'melody': pattern = generateMelodyPattern(option); break;
        case 'harmony': pattern = generateHarmonyPattern(option); break;
        case 'bass': pattern = generateBassPattern(option); break;
        case 'drums': pattern = generateDrumsPattern(option); break;
        default: pattern = [];
    }

    // 合成到 offline context
    pattern.forEach((note, i) => {
        if (!note) return;
        const startTime = i * beatDur;

        if (part === 'drums') {
            renderDrumToOffline(ctx, note, startTime, volume);
        } else {
            const freq = noteFrequencies[note] || 440;
            const type = part === 'melody' ? 'sine' : 'triangle';
            const noteDur = beatDur * (part === 'melody' ? 0.8 : 0.9);

            const osc = ctx.createOscillator();
            const gain = ctx.createGain();
            osc.type = type;
            osc.frequency.value = freq;

            gain.gain.setValueAtTime(0, startTime);
            gain.gain.linearRampToValueAtTime(volume, startTime + 0.02);
            gain.gain.setValueAtTime(volume, startTime + noteDur - 0.05);
            gain.gain.exponentialRampToValueAtTime(0.001, startTime + noteDur);

            osc.connect(gain);
            gain.connect(ctx.destination);
            osc.start(startTime);
            osc.stop(startTime + noteDur);
        }
    });

    return await ctx.startRendering();
}

// 离线鼓点合成
function renderDrumToOffline(ctx, drum, startTime, volume) {
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    switch(drum) {
        case 'kick':
            osc.frequency.setValueAtTime(150, startTime);
            osc.frequency.exponentialRampToValueAtTime(0.01, startTime + 0.5);
            gain.gain.setValueAtTime(volume, startTime);
            gain.gain.exponentialRampToValueAtTime(0.001, startTime + 0.5);
            osc.start(startTime);
            osc.stop(startTime + 0.5);
            break;
        case 'snare':
            osc.type = 'triangle';
            osc.frequency.setValueAtTime(200, startTime);
            gain.gain.setValueAtTime(volume * 0.8, startTime);
            gain.gain.exponentialRampToValueAtTime(0.001, startTime + 0.15);
            osc.start(startTime);
            osc.stop(startTime + 0.15);
            break;
        case 'hihat':
            osc.type = 'square';
            osc.frequency.setValueAtTime(800, startTime);
            gain.gain.setValueAtTime(volume * 0.3, startTime);
            gain.gain.exponentialRampToValueAtTime(0.001, startTime + 0.05);
            osc.start(startTime);
            osc.stop(startTime + 0.05);
            break;
    }

    osc.connect(gain);
    gain.connect(ctx.destination);
}

