// 停止音乐实例 (立即打断)
function stopMusicVoice(part) {
    const voice = activeMusicVoices[part];
    if (voice) {
        // 停止 buffer source
        if (voice.source) {
            try {
                voice.source.stop();
                voice.source.disconnect();
            } catch(e) {}
        }
        activeMusicVoices[part] = null;
    }
}

// 开始音乐实例（使用预合成 buffer，零延迟）
function startMusicVoice(part, state, startTime) {
    const ctx = gameState.audioContext;
    const bufferKey = `${part}-${state}`;
    const buffer = audioBufferCache.buffers[bufferKey];

    if (!buffer) {
        console.error('Buffer not found:', bufferKey);
        return;
    }

    // 创建 BufferSource
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.loop = true;

    // 连接到轨道增益
    const trackGain = trackGainNodes[part] || masterGainNode;
    source.connect(trackGain);

    // 在指定时间开始
    source.start(startTime);

    // 保存引用
    activeMusicVoices[part] = {
        source: source,
        part: part,
        state: state
    };
}

