        // 确认选择（阶段2 → 阶段3）
        function confirmSelection() {
            // 检查是否所有声部都已选择
            const missing = parts.filter(p => !gameState.userSelection[p]);
            if (missing.length > 0) {
                alert('请先选择：' + missing.map(p => partNames[p]).join('、'));
                return;
            }

            // 播放阶段切换音效
            playPhaseTransitionStinger(3);

            gameState.currentPhase = 3;
            updateStageIndicator();

            document.getElementById('phase2').style.display = 'none';
            document.getElementById('phase3').style.display = 'block';

            // 停止播放（旧系统 + Wwise 系统）
            clearAllLoops();
            stopAllMusic();

            // 停止所有进度条
            stopOriginalProgressBar();
            stopUserProgressBar();

            // 填充对比区域
