// ==================== Mute / Solo 控制 ====================

function toggleMute(part) {
    gameState.mutedTracks[part] = !gameState.mutedTracks[part];

    const btn = document.getElementById(part + 'Mute');
    if (gameState.mutedTracks[part]) {
        btn.classList.add('active');
        // 如果该轨道正在播放，立即静音
        if (trackGainNodes[part]) {
            trackGainNodes[part].gain.setValueAtTime(0, gameState.audioContext.currentTime);
        }
    } else {
        btn.classList.remove('active');
        // 恢复音量（如果不是被 solo 排除）
        if (trackGainNodes[part] && !isSoloExcluding(part)) {
            trackGainNodes[part].gain.setValueAtTime(MUSIC_TRACKS[part].volume, gameState.audioContext.currentTime);
        }
    }

    // 如果开启 mute，关闭 solo
    if (gameState.mutedTracks[part] && gameState.soloTrack === part) {
        toggleSolo(part);
    }
}

function toggleSolo(part) {
    if (gameState.soloTrack === part) {
        // 关闭 solo
        gameState.soloTrack = null;
        document.getElementById(part + 'Solo').classList.remove('solo-active');

        // 恢复所有非 mute 轨道的音量
        parts.forEach(p => {
            if (trackGainNodes[p] && !gameState.mutedTracks[p]) {
                trackGainNodes[p].gain.setValueAtTime(MUSIC_TRACKS[p].volume, gameState.audioContext.currentTime);
            }
        });
    } else {
        // 关闭之前的 solo
        if (gameState.soloTrack) {
            document.getElementById(gameState.soloTrack + 'Solo').classList.remove('solo-active');
        }

        // 开启新的 solo
        gameState.soloTrack = part;
        document.getElementById(part + 'Solo').classList.add('solo-active');

        // 只有 solo 轨道有音量，其他轨道静音（除了被 mute 的）
        parts.forEach(p => {
            if (trackGainNodes[p]) {
                if (p === part && !gameState.mutedTracks[p]) {
                    trackGainNodes[p].gain.setValueAtTime(MUSIC_TRACKS[p].volume, gameState.audioContext.currentTime);
                } else {
                    trackGainNodes[p].gain.setValueAtTime(0, gameState.audioContext.currentTime);
                }
            }
        });

        // 如果该轨道被 mute，取消 mute
        if (gameState.mutedTracks[part]) {
            toggleMute(part);
        }
    }
}

function isSoloExcluding(part) {
    return gameState.soloTrack && gameState.soloTrack !== part;
}

