// 开始音乐实例（使用预合成 buffer，相位锁定）
function startMusicVoice(part, state, startTime) {
    const ctx = gameState.audioContext;
    const bufferKey = `${part}-${state}`;
    const buffer = audioBufferCache.buffers[bufferKey];

    if (!buffer) {
        console.error('Buffer not found:', bufferKey);
        return;
    }

    // 计算相位锁定偏移：找出当前播放中的声部，获取其播放位置
    let offset = 0;
    const loopDuration = 4;

    // 查找当前正在播放的其他声部
    for (const p of parts) {
        if (p !== part && activeMusicVoices[p] && activeMusicVoices[p].startTime) {
            // 计算该声部已经播放了多久
            const elapsed = ctx.currentTime - activeMusicVoices[p].startTime;
            // 对 loop 时长取模，得到当前在 loop 中的位置
            offset = elapsed % loopDuration;
            break; // 找到一个参考即可
        }
    }

    // 创建 BufferSource
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.loop = true;

    // 连接到轨道增益
    const trackGain = trackGainNodes[part] || masterGainNode;
    source.connect(trackGain);

    // 应用 mute/solo 状态
    if (gameState.mutedTracks[part] || isSoloExcluding(part)) {
        trackGain.gain.setValueAtTime(0, startTime);
