// ==================== 分享功能 ====================
let shareTargetId = null;

function shareRecording(id) {
    shareTargetId = id;
    document.getElementById('shareModal').classList.add('show');
}

function closeShareModal() {
    document.getElementById('shareModal').classList.remove('show');
    document.getElementById('shareCardContainer').innerHTML = '';
    shareTargetId = null;
}

// 生成分享链接
function generateShareLink() {
    if (!shareTargetId) return;

    const recording = recordings.find(r => r.id === shareTargetId);
    if (!recording) return;

    // 将录制数据编码为Base64
    const data = JSON.stringify({
        name: recording.name,
        notes: recording.notes,
        duration: recording.duration
    });
    const encoded = btoa(encodeURIComponent(data));

    // 生成链接
    const link = `${window.location.origin}${window.location.pathname}?share=${encoded}`;
    return link;
}

function copyLink() {
    const link = generateShareLink();
    if (link) {
        // 复制到剪贴板
        if (navigator.clipboard) {
            navigator.clipboard.writeText(link).then(() => {
                showToast('链接已复制到剪贴板！');
            }).catch(() => {
                fallbackCopy(link);
            });
        } else {
            fallbackCopy(link);
        }
    }
    closeShareModal();
}

function fallbackCopy(text) {
    const textarea = document.createElement('textarea');
    textarea.value = text;
    textarea.style.position = 'fixed';
    textarea.style.opacity = '0';
    document.body.appendChild(textarea);
    textarea.select();

    try {
        document.execCommand('copy');
        showToast('链接已复制到剪贴板！');
    } catch (err) {
        showToast('复制失败，请手动复制');
        alert('分享链接：' + text);
    }

    document.body.removeChild(textarea);
}

// 生成分享卡片
function generateShareCard() {
    if (!shareTargetId) return;

    const recording = recordings.find(r => r.id === shareTargetId);
    if (!recording) return;

    const container = document.getElementById('shareCardContainer');
    container.innerHTML = '';

    // 创建canvas
    const canvas = document.createElement('canvas');
    canvas.width = 600;
    canvas.height = 400;
    const ctx = canvas.getContext('2d');

    // 背景渐变
    const gradient = ctx.createLinearGradient(0, 0, 0, 400);
    gradient.addColorStop(0, '#1a1a2e');
    gradient.addColorStop(0.5, '#16213e');
    gradient.addColorStop(1, '#0f3460');
    ctx.fillStyle = gradient;
    ctx.fillRect(0, 0, 600, 400);

    // 边框
    ctx.strokeStyle = '#f5af19';
    ctx.lineWidth = 4;
    ctx.strokeRect(10, 10, 580, 380);

    // 标题
    ctx.fillStyle = '#f5af19';
    ctx.font = 'bold 36px "Microsoft YaHei", sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText('🔔 编钟模拟器', 300, 70);

    // 分隔线
    ctx.strokeStyle = 'rgba(245, 175, 25, 0.3)';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(100, 90);
    ctx.lineTo(500, 90);
    ctx.stroke();

    // 演奏信息
    ctx.fillStyle = '#fff';
    ctx.font = '24px "Microsoft YaHei", sans-serif';
    ctx.fillText(recording.name, 300, 140);

    ctx.font = '18px "Microsoft YaHei", sans-serif';
    ctx.fillStyle = 'rgba(255, 255, 255, 0.8)';
    ctx.fillText(`⏱️ ${recording.duration}秒 · 🎵 ${recording.notes.length}个音符`, 300, 175);
    ctx.fillText(`📅 ${recording.date}`, 300, 205);

    // 提示文字
    ctx.fillStyle = '#00d2d3';
    ctx.font = '20px "Microsoft YaHei", sans-serif';
    ctx.fillText('扫码收听我的编钟演奏', 300, 260);

    // 生成二维码（简化版）
    drawSimpleQR(ctx, 250, 280, 100);

    // 底部文字
    ctx.fillStyle = 'rgba(255, 255, 255, 0.5)';
    ctx.font = '14px "Microsoft YaHei", sans-serif';
