    const img = document.createElement('img');
    img.src = canvas.toDataURL('image/png');
    img.style.width = '100%';
    img.style.borderRadius = '10px';
    img.style.marginTop = '15px';
    container.appendChild(img);

    // 添加保存按钮
    const saveBtn = document.createElement('button');
    saveBtn.className = 'btn btn-primary';
    saveBtn.style.width = '100%';
    saveBtn.style.marginTop = '10px';
    saveBtn.textContent = '💾 保存图片';
    saveBtn.onclick = () => {
        const a = document.createElement('a');
        a.href = canvas.toDataURL('image/png');
        a.download = `编钟演奏-${recording.name}.png`;
        a.click();
        showToast('图片已保存！');
    };
    container.appendChild(saveBtn);

    showToast('分享卡片已生成！');
}

// 简化版二维码绘制
function drawSimpleQR(ctx, x, y, size) {
    ctx.fillStyle = '#fff';
    ctx.fillRect(x, y, size, size);
    ctx.fillStyle = '#000';

    const cellSize = size / 25;
    for (let i = 0; i < 25; i++) {
        for (let j = 0; j < 25; j++) {
            if (Math.random() > 0.5) {
                ctx.fillRect(x + i * cellSize, y + j * cellSize, cellSize, cellSize);
            }
        }
    }

    // 定位点
    ctx.fillStyle = '#000';
    // 左上
    ctx.fillRect(x + 2 * cellSize, y + 2 * cellSize, 5 * cellSize, 5 * cellSize);
    ctx.fillStyle = '#fff';
    ctx.fillRect(x + 3 * cellSize, y + 3 * cellSize, 3 * cellSize, 3 * cellSize);
    ctx.fillStyle = '#000';
    ctx.fillRect(x + 4 * cellSize, y + 4 * cellSize, cellSize, cellSize);

    // 右上
    ctx.fillRect(x + 18 * cellSize, y + 2 * cellSize, 5 * cellSize, 5 * cellSize);
    ctx.fillStyle = '#fff';
    ctx.fillRect(x + 19 * cellSize, y + 3 * cellSize, 3 * cellSize, 3 * cellSize);
    ctx.fillStyle = '#000';
    ctx.fillRect(x + 20 * cellSize, y + 4 * cellSize, cellSize, cellSize);

    // 左下
    ctx.fillRect(x + 2 * cellSize, y + 18 * cellSize, 5 * cellSize, 5 * cellSize);
    ctx.fillStyle = '#fff';
    ctx.fillRect(x + 3 * cellSize, y + 19 * cellSize, 3 * cellSize, 3 * cellSize);
    ctx.fillStyle = '#000';
    ctx.fillRect(x + 4 * cellSize, y + 20 * cellSize, cellSize, cellSize);
}

