function downloadRecording() {
    const recording = recordings.find(r => r.id === shareTargetId);
    if (!recording) return;

    // 导出为JSON
    const data = JSON.stringify(recording, null, 2);
    const blob = new Blob([data], { type: 'application/json' });
    const url = URL.createObjectURL(blob);

    const a = document.createElement('a');
    a.href = url;
    a.download = `编钟演奏-${recording.name}.json`;
    a.click();

    URL.revokeObjectURL(url);
    showToast('演奏数据已导出！');
    closeShareModal();
}

// 检查URL参数，加载分享的演奏
function checkSharedRecording() {
    const params = new URLSearchParams(window.location.search);
    const shareData = params.get('share');

    if (shareData) {
        try {
            const decoded = decodeURIComponent(atob(shareData));
            const recording = JSON.parse(decoded);

            // 添加到录制列表
            recording.id = Date.now();
            recording.date = '来自分享';
            recordings.push(recording);
            localStorage.setItem('bianzhong_recordings', JSON.stringify(recordings));
            updateRecordingList();

            showToast('已加载分享的演奏！');

            // 播放
            setTimeout(() => {
                playRecording(recording);
            }, 1000);
        } catch (e) {
            console.error('加载分享失败:', e);
            showToast('分享链接无效');
        }
    }
}

